import{_ as r,o as l,c as a,ag as o}from"./chunks/framework.CQYuu_FX.js";const b=JSON.parse('{"title":"Part 2 — スタッフ管理","description":"","frontmatter":{"title":"Part 2 — スタッフ管理","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1","last_updated":"2026-04-30T00:00:00.000Z"},"headers":[],"relativePath":"operations/part2-staff.md","filePath":"operations/part2-staff.md"}'),i={name:"operations/part2-staff.md"};function d(n,t,e,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="part-2-—-スタッフ管理" tabindex="-1">Part 2 — スタッフ管理 <a class="header-anchor" href="#part-2-—-スタッフ管理" aria-label="Permalink to &quot;Part 2 — スタッフ管理&quot;">​</a></h1><p>このページでは、スタッフのアカウント作成・シフト管理・勤怠打刻を、<strong>指の動きを 1 つずつ</strong> 順番に説明します。</p><div class="tip custom-block"><p class="custom-block-title">POSLA の鉄則: 1 人 1 アカウント</p><p><strong>絶対に「キッチン」「ホール」のような共有アカウントを作らないでください</strong>。以下が全部壊れます。</p><ul><li>勤怠打刻（誰が出勤したか分からない）</li><li>監査ログ（誰が操作したか記録されない）</li><li>スタッフ評価レポート（全員のデータが混ざる）</li><li>シフト管理（個別割当不可）</li></ul><p>必ず <strong>スタッフ 1 人につき 1 つのアカウント</strong> を作成してください。</p></div><div class="warning custom-block"><p class="custom-block-title">個人スマホは業務に使わない</p><p>POSLA の運用前提は、ハンディ・KDS・レジは <strong>全て店舗が用意する備品端末</strong> です。スタッフ個人のスマートフォンを業務に使う BYOD 運用は推奨しません（労務・セキュリティ・紛失時補償の問題を避けるため）。ハンディ端末は店舗が複数台購入して device アカウントでログインしっぱなしで運用するのが標準です。</p></div><hr><h2 id="_2-0-作成できるアカウントの種類-4-種類" tabindex="-1">2-0. 作成できるアカウントの種類（4 種類） <a class="header-anchor" href="#_2-0-作成できるアカウントの種類-4-種類" aria-label="Permalink to &quot;2-0. 作成できるアカウントの種類（4 種類）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>役割</th><th>作成可能者</th></tr></thead><tbody><tr><td><strong>オーナー (owner)</strong></td><td>代表者・全店舗統括</td><td>通常は POSLA 運営が契約時に発行。既存 owner から追加作成も可</td></tr><tr><td><strong>マネージャー (manager)</strong></td><td>店長・店舗運営</td><td><strong>オーナーのみ作成可</strong></td></tr><tr><td><strong>スタッフ (staff)</strong></td><td>アルバイト・社員</td><td><strong>オーナーまたはマネージャーが作成可</strong></td></tr><tr><td><strong>デバイス (device)</strong></td><td>端末専用アカウント（KDS / レジ / ハンディ）</td><td><strong>オーナーまたはマネージャーが作成可</strong></td></tr></tbody></table><h2 id="_2-1-新しいスタッフのアカウントを作る" tabindex="-1">2-1. 新しいスタッフのアカウントを作る <a class="header-anchor" href="#_2-1-新しいスタッフのアカウントを作る" aria-label="Permalink to &quot;2-1. 新しいスタッフのアカウントを作る&quot;">​</a></h2><h3 id="_2-1-1-手順-マネージャーの場合" tabindex="-1">2-1-1. 手順（マネージャーの場合） <a class="header-anchor" href="#_2-1-1-手順-マネージャーの場合" aria-label="Permalink to &quot;2-1-1. 手順（マネージャーの場合）&quot;">​</a></h3><ol><li>管理画面にマネージャーでログイン</li><li>上部タブ <strong>【店舗設定】</strong> → サブタブ <strong>【スタッフ管理】</strong></li><li>画面右上の <strong>【+ 追加】</strong> ボタン</li><li>「スタッフ追加」モーダルが開く</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td><strong>表示名</strong></td><td>—</td><td>「田中 太郎」等（後でも変更可）</td></tr><tr><td><strong>ユーザー名</strong></td><td>✅</td><td>半角英数・ハイフン・アンダースコア 3〜50 文字（例: <code>tanaka01</code>）</td></tr><tr><td><strong>メール</strong></td><td>—</td><td>任意（通知送信用）</td></tr><tr><td><strong>パスワード</strong></td><td>✅</td><td>8 文字以上 + 英字 + 数字必須</td></tr><tr><td><strong>時給</strong></td><td>—</td><td>人件費レポート用（円 / 時、1〜10000）</td></tr><tr><td><strong>ビジブルツール</strong></td><td>—</td><td>通常は空欄（staff には不要）</td></tr></tbody></table><ol start="6"><li><strong>【保存】</strong> ボタン</li><li>スタッフに <strong>ユーザー名 + パスワード</strong> を口頭またはメモで伝える</li><li>スタッフは初回ログイン後、自分で好きなパスワードに変更（推奨）</li></ol><h3 id="_2-1-2-手順-オーナーの場合" tabindex="-1">2-1-2. 手順（オーナーの場合） <a class="header-anchor" href="#_2-1-2-手順-オーナーの場合" aria-label="Permalink to &quot;2-1-2. 手順（オーナーの場合）&quot;">​</a></h3><p>オーナーはオーナー管理画面からマネージャー・スタッフを作成できます。</p><ol><li>オーナーでオーナー管理画面にログイン</li><li>上部タブ <strong>【ユーザー管理】</strong></li><li><strong>【+ ユーザー追加】</strong> ボタン</li><li>モーダル: <ul><li>表示名</li><li>ユーザー名</li><li>メール（任意）</li><li>パスワード</li><li><strong>ロール</strong>: <code>manager</code> または <code>staff</code> のどちらか選択</li><li><strong>担当店舗</strong>: 複数チェックボックス（所属店舗）</li></ul></li><li><strong>【保存】</strong></li></ol><h3 id="_2-1-3-ユーザー名の命名ルール" tabindex="-1">2-1-3. ユーザー名の命名ルール <a class="header-anchor" href="#_2-1-3-ユーザー名の命名ルール" aria-label="Permalink to &quot;2-1-3. ユーザー名の命名ルール&quot;">​</a></h3><ul><li><strong>半角英数字 + ハイフン + アンダースコア</strong> のみ</li><li><strong>3〜50 文字</strong></li><li><strong>POSLA 全体で一意</strong>。同じ店舗内だけでなく、他店舗・他テナントと重複する場合も登録できない</li></ul><div class="warning custom-block"><p class="custom-block-title">ユーザー名はPOSLA全体で一意です</p><p>他社・他店舗で同じユーザー名が使われている場合も登録できません。店舗名や会社名の略号を付けると重複しにくくなります（例: <code>matsunoya_tanaka01</code>, <code>momonoya_suzuki-hall</code>）。</p></div><p><strong>推奨パターン</strong>:</p><ul><li><code>&lt;テナント略号&gt;_tanaka01</code>, <code>&lt;テナント略号&gt;_suzuki-hall</code>（人間の場合、名前 + 番号 or 役割）</li><li><code>kds-shibuya-01</code>, <code>register-ginza-01</code>, <code>handy-shinjuku-02</code>（device の場合、役割 + 店舗 + 番号）</li></ul><h3 id="_2-1-4-失敗時のエラー" tabindex="-1">2-1-4. 失敗時のエラー <a class="header-anchor" href="#_2-1-4-失敗時のエラー" aria-label="Permalink to &quot;2-1-4. 失敗時のエラー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>メッセージ</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>「ユーザー名は既に使用されています」</td><td>同名アカウントあり</td><td>別のユーザー名（例: tanaka01 → tanaka02）</td></tr><tr><td>「パスワードは8文字以上で入力してください」</td><td>短い</td><td>8 文字以上にする</td></tr><tr><td>「パスワードには英字を1文字以上含めてください」</td><td>数字のみ</td><td>英字を混ぜる</td></tr><tr><td>「パスワードには数字を1文字以上含めてください」</td><td>英字のみ</td><td>数字を混ぜる</td></tr><tr><td>「ユーザー名は半角英数字・ハイフン・アンダースコア（3〜50文字）で入力してください」</td><td>形式違反</td><td>正しい形式に</td></tr><tr><td>「メールアドレスの形式が正しくありません」</td><td>メール入力ミス</td><td>正しいメール形式に（任意なので空欄 OK）</td></tr></tbody></table><hr><h2 id="_2-1-b-スタッフのレジ担当-pin-を設定する" tabindex="-1">2-1-b. スタッフのレジ担当 PIN を設定する <a class="header-anchor" href="#_2-1-b-スタッフのレジ担当-pin-を設定する" aria-label="Permalink to &quot;2-1-b. スタッフのレジ担当 PIN を設定する&quot;">​</a></h2><p>POSレジで「誰が操作したか」を特定するため、各スタッフに <strong>4〜8 桁の PIN</strong> を設定します。</p><div class="warning custom-block"><p class="custom-block-title">マネージャーも全員 PIN 設定が必須</p><p><strong>マネージャー / オーナーであっても自分の PIN 設定が必須</strong>になりました。レジ金庫操作（レジ開け / レジ閉め / 入金 / 出金）にも PIN が要求されるため、PIN を設定していないマネージャーは開店作業ができません。</p><p>「会計用だけ」と思って未設定のままにしていたマネージャーは、<strong>今すぐ自分の PIN を設定</strong>してください。</p></div><h3 id="pin-が必要な操作の一覧" tabindex="-1">PIN が必要な操作の一覧 <a class="header-anchor" href="#pin-が必要な操作の一覧" aria-label="Permalink to &quot;PIN が必要な操作の一覧&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>PIN 必須</th></tr></thead><tbody><tr><td>会計確定（現金 / カード / QR / Terminal）</td><td>✅</td></tr><tr><td>返金処理（部分・全額）</td><td>✅</td></tr><tr><td><strong>レジ開け</strong></td><td><strong>✅</strong></td></tr><tr><td><strong>レジ閉め</strong></td><td><strong>✅</strong></td></tr><tr><td><strong>入金（Cash In）</strong></td><td><strong>✅</strong></td></tr><tr><td><strong>出金（Cash Out）</strong></td><td><strong>✅</strong></td></tr></tbody></table><h3 id="設定手順-店長向け" tabindex="-1">設定手順（店長向け） <a class="header-anchor" href="#設定手順-店長向け" aria-label="Permalink to &quot;設定手順（店長向け）&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【スタッフ管理】</li><li>対象スタッフの <strong>【編集】</strong> ボタン</li><li>編集モーダル内の <strong>「レジ担当 PIN」</strong> 欄に 4〜8 桁の数字を入力</li><li><strong>【保存】</strong> ボタン</li><li>スタッフに PIN を口頭で伝える</li><li>スタッフは初回ログイン時に自分で別の PIN に変更推奨</li></ol><h3 id="スタッフ自身による-pin-変更" tabindex="-1">スタッフ自身による PIN 変更 <a class="header-anchor" href="#スタッフ自身による-pin-変更" aria-label="Permalink to &quot;スタッフ自身による PIN 変更&quot;">​</a></h3><ol><li>スタッフ（マネージャー含む）が管理画面にログイン</li><li>同じ手順で自分の <strong>【編集】</strong> ボタン</li><li>「レジ担当 PIN」欄に新しい PIN を入力 → <strong>【保存】</strong></li></ol><h3 id="注意事項" tabindex="-1">注意事項 <a class="header-anchor" href="#注意事項" aria-label="Permalink to &quot;注意事項&quot;">​</a></h3><ul><li>✅ <strong>退勤時は必ず退勤打刻</strong>: 退勤したスタッフの PIN は <strong>自動無効化</strong> される（不正悪用防止）</li><li>✅ <strong>マネージャーも開店前に出勤打刻が必須</strong>（出勤打刻していないと自分の PIN でレジ開けできない）</li><li>✅ 弱い PIN は登録不可（<code>1234</code>、<code>0000</code>、ゾロ目などはエラー）</li><li>✅ PIN は他人に教えない、付箋でレジに貼らない</li><li>✅ 半年〜1 年で変更推奨</li></ul><p>詳細は <a href="./../tenant/02-login.html">2 章 2.6 担当スタッフ PIN</a> / <a href="./../tenant/08-cashier.html#86-レジ開閉操作">8 章 8.6 レジ開閉操作</a> 参照。</p><hr><h2 id="_2-2-スタッフのパスワードをリセットする" tabindex="-1">2-2. スタッフのパスワードをリセットする <a class="header-anchor" href="#_2-2-スタッフのパスワードをリセットする" aria-label="Permalink to &quot;2-2. スタッフのパスワードをリセットする&quot;">​</a></h2><p>スタッフが「パスワードを忘れた」と言ってきた時。</p><h3 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【スタッフ管理】</li><li>該当スタッフの行を探す</li><li><strong>【編集】</strong> ボタン</li><li>編集モーダルが開く</li><li><strong>【新しいパスワード】</strong> 欄に新しいパスワード（8 文字以上 + 英字 + 数字）を入力</li><li><strong>【保存】</strong></li><li>スタッフに新パスワードを口頭で伝える</li><li>スタッフは次回ログイン後、自分で変更してもらう</li></ol><div class="warning custom-block"><p class="custom-block-title">新パスワードを平文でメモ・メール送信しない</p><p>セキュリティリスクがあるので、口頭で伝えるのが基本。メモでも必ず破棄。メール送信時は暗号化メッセージで。</p></div><hr><h2 id="_2-3-スタッフを削除する-退職時" tabindex="-1">2-3. スタッフを削除する（退職時） <a class="header-anchor" href="#_2-3-スタッフを削除する-退職時" aria-label="Permalink to &quot;2-3. スタッフを削除する（退職時）&quot;">​</a></h2><h3 id="推奨-削除ではなく-無効化" tabindex="-1">推奨: 削除ではなく <strong>無効化</strong> <a class="header-anchor" href="#推奨-削除ではなく-無効化" aria-label="Permalink to &quot;推奨: 削除ではなく **無効化**&quot;">​</a></h3><p>監査ログの履歴を維持するため、<strong>アカウントを物理削除せず、無効化する運用</strong> を推奨します。</p><h3 id="_2-3-1-無効化の手順" tabindex="-1">2-3-1. 無効化の手順 <a class="header-anchor" href="#_2-3-1-無効化の手順" aria-label="Permalink to &quot;2-3-1. 無効化の手順&quot;">​</a></h3><ol><li>【スタッフ管理】 で該当スタッフの <strong>【編集】</strong></li><li><strong>「有効/無効」トグル</strong> を <strong>【無効】</strong> にする</li><li><strong>【保存】</strong></li><li>以降、このスタッフはログインできなくなる</li><li>過去の注文・勤怠・操作履歴はすべて保持される</li></ol><h3 id="_2-3-2-完全削除-非推奨" tabindex="-1">2-3-2. 完全削除（非推奨） <a class="header-anchor" href="#_2-3-2-完全削除-非推奨" aria-label="Permalink to &quot;2-3-2. 完全削除（非推奨）&quot;">​</a></h3><p>どうしても完全削除したい場合:</p><ol><li>編集画面で <strong>【削除】</strong> ボタン（赤）</li><li>確認ダイアログで <strong>【OK】</strong></li><li>アカウントが削除される</li></ol><div class="danger custom-block"><p class="custom-block-title">注意</p><p>完全削除すると、過去の注文・勤怠・操作履歴とのつながりが確認しづらくなる場合があります。税務監査・労務管理の観点から <strong>無効化を推奨</strong> します。</p></div><hr><h2 id="_2-4-デバイスアカウント-kds-レジ-ハンディ端末専用-の作り方" tabindex="-1">2-4. デバイスアカウント（KDS / レジ / ハンディ端末専用）の作り方 <a class="header-anchor" href="#_2-4-デバイスアカウント-kds-レジ-ハンディ端末専用-の作り方" aria-label="Permalink to &quot;2-4. デバイスアカウント（KDS / レジ / ハンディ端末専用）の作り方&quot;">​</a></h2><p>「人」ではなく「端末」のためのアカウントです。</p><h3 id="_2-4-1-デバイスアカウントの特徴" tabindex="-1">2-4-1. デバイスアカウントの特徴 <a class="header-anchor" href="#_2-4-1-デバイスアカウントの特徴" aria-label="Permalink to &quot;2-4-1. デバイスアカウントの特徴&quot;">​</a></h3><ul><li>ログインしっぱなし前提（端末再起動時のみ再ログイン）</li><li>シフト・人件費・スタッフ評価レポートの対象外（人間ではないため）</li><li>監査ログには端末用アカウントとして記録される</li><li>管理画面には入れない（KDS / レジ / ハンディのいずれかに直接遷移）</li></ul><h3 id="_2-4-2-作成手順" tabindex="-1">2-4-2. 作成手順 <a class="header-anchor" href="#_2-4-2-作成手順" aria-label="Permalink to &quot;2-4-2. 作成手順&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【スタッフ管理】</li><li>画面を下にスクロール → <strong>「デバイスアカウント」セクション</strong></li><li><strong>【+ デバイス追加】</strong> ボタン</li><li>モーダル:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td><strong>表示名</strong></td><td>✅</td><td>「厨房KDS 1番」「レジ-渋谷-01」等の人間向けの名前</td></tr><tr><td><strong>ユーザー名</strong></td><td>✅</td><td><code>kds-shibuya-01</code> 等（英数字・ハイフン、3〜50 文字）</td></tr><tr><td><strong>パスワード</strong></td><td>✅</td><td>8 文字以上 + 英字 + 数字</td></tr><tr><td><strong>用途</strong></td><td>✅</td><td>チェックボックス: KDS / POSレジ / ハンディ から <strong>少なくとも 1 つ</strong></td></tr></tbody></table><ol start="5"><li><strong>【保存】</strong></li><li>一覧に追加される</li></ol><h3 id="_2-4-3-用途の組み合わせによる遷移先" tabindex="-1">2-4-3. 用途の組み合わせによる遷移先 <a class="header-anchor" href="#_2-4-3-用途の組み合わせによる遷移先" aria-label="Permalink to &quot;2-4-3. 用途の組み合わせによる遷移先&quot;">​</a></h3><p>デバイスアカウントがログインした後の遷移先は、作成時に選んだ用途で決まります。</p><table tabindex="0"><thead><tr><th>用途</th><th>ログイン後の画面</th></tr></thead><tbody><tr><td>ハンディ</td><td>ハンディ画面</td></tr><tr><td>POSレジ</td><td>POSレジ画面</td></tr><tr><td>KDS</td><td>KDS画面</td></tr><tr><td>複数用途を選んだ場合</td><td>ハンディ、POSレジ、KDSの順で優先表示</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">1 端末 1 用途を強く推奨</p><p>複数選択は技術的に可能ですが、<strong>運用上は 1 端末 1 用途</strong>（KDS のみ / POSレジ のみ / ハンディのみ）にしてください。KDS 画面表示中に会計が来て切替えたらピックアップ画面が消える、といった事故が起きます。</p></div><h3 id="_2-4-4-ワンタイムトークンで端末を自動セットアップする" tabindex="-1">2-4-4. ワンタイムトークンで端末を自動セットアップする <a class="header-anchor" href="#_2-4-4-ワンタイムトークンで端末を自動セットアップする" aria-label="Permalink to &quot;2-4-4. ワンタイムトークンで端末を自動セットアップする&quot;">​</a></h3><p>新しい KDS / レジ / ハンディタブレットを設置する時、手動でユーザー名・パスワードを入力する代わりに <strong>ワンタイムトークン</strong>で自動ログインできます。</p><h4 id="手順-1" tabindex="-1">手順 <a class="header-anchor" href="#手順-1" aria-label="Permalink to &quot;手順&quot;">​</a></h4><ol><li>管理画面 → 【スタッフ管理】 → デバイスアカウントセクション</li><li><strong>【トークン発行】</strong> ボタン</li><li>ダイアログで端末の「表示名」と「用途」を入力</li><li>セットアップ用URLが表示される</li><li><strong>URL を新しい端末で開く</strong>（手動コピー、または QR にして読み取り）</li><li>POSLAが端末用アカウントを自動作成する</li><li>用途に合わせて、KDS / レジ / ハンディの画面へ自動で移動する</li></ol><h4 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h4><ul><li>セットアップURLは1回だけ使えます</li><li>期限が切れた場合は、もう一度【トークン発行】を押してください</li><li>URLを店外や関係者以外に共有しないでください</li></ul><h3 id="_2-4-5-スタッフアカウントとの違い" tabindex="-1">2-4-5. スタッフアカウントとの違い <a class="header-anchor" href="#_2-4-5-スタッフアカウントとの違い" aria-label="Permalink to &quot;2-4-5. スタッフアカウントとの違い&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>スタッフアカウント</th><th>デバイスアカウント</th></tr></thead><tbody><tr><td>想定用途</td><td>人間 1 人</td><td>端末 1 台</td></tr><tr><td>シフト管理対象</td><td>✅</td><td>❌</td></tr><tr><td>人件費計算対象</td><td>✅</td><td>❌</td></tr><tr><td>スタッフ評価レポート</td><td>✅</td><td>❌</td></tr><tr><td>GPS 打刻必須</td><td>店舗設定による</td><td><strong>常に必須</strong>（セキュリティ）</td></tr><tr><td>管理画面アクセス</td><td>限定（予約・シフト 2 タブのみ）</td><td>✗ 不可</td></tr></tbody></table><hr><h2 id="_2-5-シフトの作成と公開" tabindex="-1">2-5. シフトの作成と公開 <a class="header-anchor" href="#_2-5-シフトの作成と公開" aria-label="Permalink to &quot;2-5. シフトの作成と公開&quot;">​</a></h2><p>シフトの作成は <strong>「シフト管理」タブ</strong> から行います（manager 以上）。</p><h3 id="_2-5-1-シフトを作る手順" tabindex="-1">2-5-1. シフトを作る手順 <a class="header-anchor" href="#_2-5-1-シフトを作る手順" aria-label="Permalink to &quot;2-5-1. シフトを作る手順&quot;">​</a></h3><ol><li>管理画面 → 上部タブ <strong>【シフト管理】</strong></li><li>サブタブ <strong>【週間カレンダー】</strong></li><li>画面上部の日付切替ボタンで該当週を表示</li><li>スタッフ名 × 日付のグリッドが表示される</li><li>セル（スタッフ × 日）をタップ</li><li>シフト入力モーダル:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>開始時刻</strong></td><td>例: <code>10:00</code></td></tr><tr><td><strong>終了時刻</strong></td><td>例: <code>18:00</code></td></tr><tr><td><strong>休憩</strong></td><td>分単位。6 時間超、8 時間超の勤務は公開前チェックでも警告される</td></tr><tr><td><strong>持ち場</strong></td><td>ホール、キッチン、ドリンク、洗い場など店舗で設定した持ち場。指定なしも可</td></tr><tr><td><strong>メモ</strong></td><td>任意（例: 「研修日」）</td></tr></tbody></table><ol start="7"><li><strong>【保存】</strong></li><li>セルに色付きでシフトが表示される</li></ol><h3 id="_2-5-2-全員分入力できたら公開前チェック" tabindex="-1">2-5-2. 全員分入力できたら公開前チェック <a class="header-anchor" href="#_2-5-2-全員分入力できたら公開前チェック" aria-label="Permalink to &quot;2-5-2. 全員分入力できたら公開前チェック&quot;">​</a></h3><p>週間カレンダーの上部に <strong>公開前チェック</strong> が表示されます。ここでは、確定前に以下をまとめて確認します。</p><table tabindex="0"><thead><tr><th>確認項目</th><th>内容</th></tr></thead><tbody><tr><td>時間帯ごとの人数不足</td><td>テンプレート必要人数、過去 8 週間の同曜日・同時間帯売上、対象日の予約人数を使って必要人数を出し、予定人数と比較</td></tr><tr><td>持ち場不足</td><td>テンプレートで持ち場を指定した時間帯について、予定シフトの持ち場数と比較</td></tr><tr><td>休憩未設定/不足</td><td>6 時間超は 45 分、8 時間超は 60 分を目安に警告</td></tr><tr><td>希望未提出</td><td>対象週の希望提出がない、または一部の日だけ未提出のスタッフを表示</td></tr><tr><td>未確認シフト</td><td>確定したがスタッフがマイシフトで <strong>確認</strong> を押していないシフトを表示</td></tr><tr><td>予定人件費率</td><td>予定シフトの人件費目安を過去売上平均と比較。店舗設定の目標人件費率を超えると警告</td></tr><tr><td>労務リスク</td><td>予定上の週 40 時間超、1 日 8 時間超、6 日以上連続勤務を表示</td></tr><tr><td>実績差分</td><td>過去日について、予定 vs 勤怠打刻の遅刻・早退・残業・打刻なしを表示</td></tr><tr><td>ヘルプ候補</td><td>不足時間帯について、他店舗スタッフ候補を表示</td></tr></tbody></table><p>赤または黄色の警告が残っていても、現場判断で公開できます。ただし、赤の警告は公開前に必ず内容を確認してください。</p><h3 id="_2-5-3-公開する" tabindex="-1">2-5-3. 公開する <a class="header-anchor" href="#_2-5-3-公開する" aria-label="Permalink to &quot;2-5-3. 公開する&quot;">​</a></h3><ol><li>公開前チェックを確認</li><li>必要に応じてシフト、休憩、持ち場を修正</li><li>画面上部の <strong>【確定する】</strong> ボタン</li><li>確認ダイアログ → <strong>【OK】</strong></li><li>以降、スタッフは <strong>マイシフト</strong> で自分のシフトを確認できる</li><li>スタッフは内容を見て <strong>確認</strong> を押す</li><li>店長は公開前チェックの未確認一覧で、まだ確認していないスタッフを確認する</li></ol><p>この操作だけでは外部メッセージ通知は送られません。希望未提出者への連絡は、公開前チェックの <strong>リマインド文コピー</strong> を使い、店舗の通常連絡手段で送ってください。</p><h3 id="_2-5-4-ai-シフト提案を使う" tabindex="-1">2-5-4. AI シフト提案を使う <a class="header-anchor" href="#_2-5-4-ai-シフト提案を使う" aria-label="Permalink to &quot;2-5-4. AI シフト提案を使う&quot;">​</a></h3><p>過去の売上データとスタッフの希望から、最適なシフトを AI が自動生成する機能。</p><ol><li>カレンダー画面上部の <strong>【AI 提案】</strong> ボタン</li><li>AI が数秒で全スタッフのシフト案を生成</li><li>内容を画面で確認</li><li><strong>【全て採用】</strong> ボタンで一括反映（既存の手動シフトは上書きされない）</li><li>内容を調整し、公開前チェックを確認</li><li><strong>【確定する】</strong> で公開</li></ol><p>AI 提案を使わなくても、公開前チェック、必要人数表示、希望未提出、実績差分、予定人件費率、労務リスク、ヘルプ候補は動きます。</p><h3 id="_2-5-5-持ち場を整える" tabindex="-1">2-5-5. 持ち場を整える <a class="header-anchor" href="#_2-5-5-持ち場を整える" aria-label="Permalink to &quot;2-5-5. 持ち場を整える&quot;">​</a></h3><p>持ち場は <strong>シフト設定</strong> で管理します。初期状態はホール、キッチンです。</p><p>店舗に合わせて、ドリンク、洗い場、レジ、仕込みなどを追加できます。</p><ol><li>管理画面 → 【シフト管理】 → <strong>【シフト設定】</strong></li><li>画面内の <strong>持ち場</strong> を見る</li><li>code と表示名を入力する <ul><li>code: <code>drink</code>、<code>wash</code> など英数字・<code>_</code>・<code>-</code> の 20 文字以内</li><li>表示名: 画面に出る名前（例: ドリンク、洗い場）</li></ul></li><li><strong>追加</strong> を押す</li><li>テンプレートや週間カレンダーの持ち場選択に出る</li></ol><p>使わなくなった持ち場は <strong>非表示</strong> にします。過去シフトの履歴は残ります。</p><h3 id="_2-5-6-目標人件費率を設定する" tabindex="-1">2-5-6. 目標人件費率を設定する <a class="header-anchor" href="#_2-5-6-目標人件費率を設定する" aria-label="Permalink to &quot;2-5-6. 目標人件費率を設定する&quot;">​</a></h3><p>公開前チェックと集計サマリーの警告基準として、店舗の目標人件費率を設定できます。</p><ol><li>管理画面 → 【シフト管理】 → <strong>【シフト設定】</strong></li><li><strong>目標人件費率</strong> に数値を入力（例: 30）</li><li>店舗デフォルト時給も未設定なら入力</li><li><strong>保存</strong> を押す</li></ol><p>公開前チェックの予定人件費率は、予定シフトの人件費を過去売上平均で割って計算します。予約人数は必要人数の判定に使いますが、予約金額として自動換算はしません。</p><hr><h2 id="_2-6-出退勤の打刻方法と確認" tabindex="-1">2-6. 出退勤の打刻方法と確認 <a class="header-anchor" href="#_2-6-出退勤の打刻方法と確認" aria-label="Permalink to &quot;2-6. 出退勤の打刻方法と確認&quot;">​</a></h2><h3 id="_2-6-1-スタッフの打刻" tabindex="-1">2-6-1. スタッフの打刻 <a class="header-anchor" href="#_2-6-1-スタッフの打刻" aria-label="Permalink to &quot;2-6-1. スタッフの打刻&quot;">​</a></h3><p>スタッフ側の操作。</p><ol><li>管理画面（<code>/admin/</code>）に staff アカウントでログイン</li><li>デフォルト表示される「スタッフ画面」で、今日の勤務、未対応、打刻状態を確認</li><li><strong>【出勤する】</strong> ボタンをタップ</li><li><strong>GPS 許可ダイアログ</strong> が出たら <strong>【許可】</strong></li><li>店舗から半径 200m 以内（デフォルト）にいるか判定</li><li>OK なら勤務中表示になる</li><li>退勤時は <strong>【退勤する】</strong> ボタンをタップ</li></ol><p>スタッフ画面には、変更未確認シフト、担当作業、募集シフト、交代/欠勤申請、打刻修正申請も表示されます。出勤前に未対応がないか確認してください。</p><h3 id="_2-6-2-スタッフの打刻修正申請" tabindex="-1">2-6-2. スタッフの打刻修正申請 <a class="header-anchor" href="#_2-6-2-スタッフの打刻修正申請" aria-label="Permalink to &quot;2-6-2. スタッフの打刻修正申請&quot;">​</a></h3><p>打刻忘れや時刻誤りがある場合、スタッフ本人がスタッフ画面の <strong>勤怠履歴・修正申請</strong> から店長へ申請できます。</p><ol><li>スタッフ画面 → <strong>勤怠履歴・修正申請</strong></li><li><strong>打刻修正を申請</strong>、または対象打刻の <strong>この打刻を修正</strong></li><li>対象日、出勤時刻、退勤時刻、休憩時間、理由を入力</li><li><strong>申請する</strong></li></ol><p>申請しただけでは勤怠実績は変わりません。店長が承認した時点で勤怠一覧へ反映されます。</p><h3 id="_2-6-3-店長の勤怠確認" tabindex="-1">2-6-3. 店長の勤怠確認 <a class="header-anchor" href="#_2-6-3-店長の勤怠確認" aria-label="Permalink to &quot;2-6-3. 店長の勤怠確認&quot;">​</a></h3><ol><li>管理画面 → 【シフト管理】 → サブタブ <strong>【勤怠一覧】</strong></li><li>日別にスタッフの打刻記録が一覧表示</li><li>スタッフからの打刻修正申請がある場合、勤怠一覧の上部に表示</li><li>内容と理由を確認し、問題がなければ <strong>承認して勤怠へ反映</strong></li><li>店長が直接直す場合は、該当行の <strong>【修正】</strong> で手動修正</li><li>公開前チェックと集計サマリーで、予定（シフト）vs 実績（打刻）の遅刻・早退・残業・打刻なしを確認</li></ol><hr><h2 id="_2-7-gps-打刻の設定" tabindex="-1">2-7. GPS 打刻の設定 <a class="header-anchor" href="#_2-7-gps-打刻の設定" aria-label="Permalink to &quot;2-7. GPS 打刻の設定&quot;">​</a></h2><h3 id="_2-7-1-店舗の-gps-設定" tabindex="-1">2-7-1. 店舗の GPS 設定 <a class="header-anchor" href="#_2-7-1-店舗の-gps-設定" aria-label="Permalink to &quot;2-7-1. 店舗の GPS 設定&quot;">​</a></h3><ol><li>管理画面 → 【シフト管理】 → <strong>【シフト設定】</strong> サブタブ</li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>店舗緯度</strong></td><td>Google Maps で店舗の住所を検索 → 右クリック → 座標をコピー（例: 35.6585）</td></tr><tr><td><strong>店舗経度</strong></td><td>同上（例: 139.7454）</td></tr><tr><td><strong>GPS 許容半径</strong></td><td>デフォルト 200m</td></tr><tr><td><strong>GPS 打刻必須</strong></td><td>トグル ON/OFF</td></tr></tbody></table><ol start="3"><li><strong>【保存】</strong></li></ol><h3 id="_2-7-2-店舗座標の調べ方-google-maps" tabindex="-1">2-7-2. 店舗座標の調べ方（Google Maps） <a class="header-anchor" href="#_2-7-2-店舗座標の調べ方-google-maps" aria-label="Permalink to &quot;2-7-2. 店舗座標の調べ方（Google Maps）&quot;">​</a></h3><ol><li><a href="https://www.google.com/maps" target="_blank" rel="noreferrer">Google Maps</a> を開く</li><li>店舗の住所を検索</li><li>地図上の店舗アイコンを右クリック</li><li><strong>「座標をコピー」</strong> または表示された緯度経度の数字をメモ</li><li>例: <code>35.6585, 139.7454</code> → 緯度 35.6585 / 経度 139.7454</li></ol><h3 id="_2-7-3-device-ロールは常に-gps-必須" tabindex="-1">2-7-3. device ロールは常に GPS 必須 <a class="header-anchor" href="#_2-7-3-device-ロールは常に-gps-必須" aria-label="Permalink to &quot;2-7-3. device ロールは常に GPS 必須&quot;">​</a></h3><p>スタッフは店舗設定により GPS 打刻の必須/任意が変わりますが、<strong>デバイスアカウントは常に GPS 確認が必要</strong>です。店舗備品の端末が店外に持ち出された場合のリスクを下げるためです。</p><h3 id="_2-7-4-gps-がずれる場合" tabindex="-1">2-7-4. GPS がずれる場合 <a class="header-anchor" href="#_2-7-4-gps-がずれる場合" aria-label="Permalink to &quot;2-7-4. GPS がずれる場合&quot;">​</a></h3><ul><li>室内だと GPS 精度が落ちる（5〜50m ずれることも）</li><li>ビル内の店舗は特に誤差が大きい</li><li>対処: 許容半径を <strong>300〜500m</strong> に広げる</li><li>それでもダメなら <strong>GPS 必須を OFF</strong> にして、代わりに監査ログで出退勤を確認</li></ul><hr><h2 id="_2-8-ai-シフト提案の詳細" tabindex="-1">2-8. AI シフト提案の詳細 <a class="header-anchor" href="#_2-8-ai-シフト提案の詳細" aria-label="Permalink to &quot;2-8. AI シフト提案の詳細&quot;">​</a></h2><h3 id="_2-8-1-仕組み" tabindex="-1">2-8-1. 仕組み <a class="header-anchor" href="#_2-8-1-仕組み" aria-label="Permalink to &quot;2-8-1. 仕組み&quot;">​</a></h3><ul><li>過去 30〜90 日の売上データ分析</li><li>各時間帯の必要人員を推定</li><li>スタッフごとの希望シフト（シフト希望提出機能）との合致</li><li>労基法遵守（週40時間以下、1日8時間以下）</li></ul><h3 id="_2-8-2-使い方" tabindex="-1">2-8-2. 使い方 <a class="header-anchor" href="#_2-8-2-使い方" aria-label="Permalink to &quot;2-8-2. 使い方&quot;">​</a></h3><ol><li>シフト希望を集める（スタッフが 【希望提出】 サブタブで送信）</li><li>【週間カレンダー】で <strong>【AI 提案】</strong> ボタン</li><li>提案内容を確認</li><li>修正が必要なら手動調整</li><li>公開前チェックを確認</li><li><strong>【確定する】</strong> で確定</li></ol><h3 id="_2-8-3-注意点" tabindex="-1">2-8-3. 注意点 <a class="header-anchor" href="#_2-8-3-注意点" aria-label="Permalink to &quot;2-8-3. 注意点&quot;">​</a></h3><ul><li>AI 提案は「あくまで案」。最終判断はマネージャー</li><li>新人スタッフの研修シフト等、AI には見えない要素は手動調整</li><li>既存の手動シフトは上書きされない</li></ul><hr><h2 id="_2-9-複数店舗のシフトヘルプ" tabindex="-1">2-9. 複数店舗のシフトヘルプ <a class="header-anchor" href="#_2-9-複数店舗のシフトヘルプ" aria-label="Permalink to &quot;2-9. 複数店舗のシフトヘルプ&quot;">​</a></h2><p>owner / manager のみが使える機能。他店舗から人員を借りる仕組み。</p><h3 id="_2-9-1-ヘルプ要請を送る" tabindex="-1">2-9-1. ヘルプ要請を送る <a class="header-anchor" href="#_2-9-1-ヘルプ要請を送る" aria-label="Permalink to &quot;2-9-1. ヘルプ要請を送る&quot;">​</a></h3><ol><li>管理画面 → 【シフト管理】 → <strong>【当日・ヘルプ】</strong> サブタブ</li><li><strong>【+ ヘルプ要請】</strong> ボタン</li><li>入力: <ul><li>送信先店舗（同テナント内の他店舗から選択）</li><li>希望日時</li><li>持ち場（ホール / キッチン / 店舗で追加した持ち場 / 指定なし）</li><li>必要人数</li><li>理由・メモ</li></ul></li><li>入力欄の下に候補スタッフが表示される</li><li>候補を見て、依頼先店舗と時間帯が妥当か確認する</li><li><strong>【送信】</strong></li><li>相手店舗のマネージャーは当日・ヘルプタブで要請を確認する</li></ol><h3 id="_2-9-2-ヘルプ要請を受ける-承認する" tabindex="-1">2-9-2. ヘルプ要請を受ける / 承認する <a class="header-anchor" href="#_2-9-2-ヘルプ要請を受ける-承認する" aria-label="Permalink to &quot;2-9-2. ヘルプ要請を受ける / 承認する&quot;">​</a></h3><ol><li>相手店舗のマネージャーが【当日・ヘルプ】サブタブで要請を確認</li><li>承認できる場合 → スタッフを選択 → <strong>【承認】</strong></li><li>選ばれたスタッフは要請元の店舗で勤務できるようになる（その日だけ）</li></ol><h3 id="_2-9-3-スタッフが他店舗で働く" tabindex="-1">2-9-3. スタッフが他店舗で働く <a class="header-anchor" href="#_2-9-3-スタッフが他店舗で働く" aria-label="Permalink to &quot;2-9-3. スタッフが他店舗で働く&quot;">​</a></h3><ol><li>スタッフ本人は管理画面で自分のシフトを確認する</li><li>派遣先店舗のハンディ、KDS、POSレジは、派遣先店舗が用意したデバイスアカウント端末を使う</li><li>会計など人の責任を記録する操作は、スタッフ本人の担当スタッフ PIN を入力する</li><li>その日は派遣先店舗のシフトで稼働</li></ol><hr><h2 id="_2-9-b-当日の不足・交代・欠勤を見る" tabindex="-1">2-9-b. 当日の不足・交代・欠勤を見る <a class="header-anchor" href="#_2-9-b-当日の不足・交代・欠勤を見る" aria-label="Permalink to &quot;2-9-b. 当日の不足・交代・欠勤を見る&quot;">​</a></h2><p>店長が当日見る画面は <strong>当日・ヘルプ</strong> です。ここに「今日対応が必要なもの」がまとまります。</p><p>画面の最上部には <strong>今日の店長チェック</strong> が出ます。これは、下の一覧を全部読まなくてもよいように、未打刻、未対応申請、欠勤穴埋め、時間帯不足、休憩不足、未完了作業、変更未確認だけを先頭に集める欄です。</p><table tabindex="0"><thead><tr><th>店長チェック</th><th>先に見る理由</th><th>対応</th></tr></thead><tbody><tr><td>遅刻/未打刻</td><td>予定開始後に打刻がない</td><td>本人確認、打刻漏れ修正、欠勤判断</td></tr><tr><td>交代・欠勤未対応</td><td>承認待ちで現場人数が確定していない</td><td>承認または却下</td></tr><tr><td>欠勤穴埋め</td><td>欠勤だけ承認され、代わりが入っていない</td><td>穴埋めボタンから候補、募集、他店舗ヘルプへ進む</td></tr><tr><td>時間帯不足</td><td>必要人数に足りない時間がある</td><td>シフト追加、店長フォロー、ヘルプ要請</td></tr><tr><td>休憩不足</td><td>休憩が未設定または不足している</td><td>休憩時間を調整</td></tr><tr><td>未完了作業</td><td>今日の担当作業が残っている</td><td>担当者へ声かけ、完了確認</td></tr><tr><td>変更未確認</td><td>変更済みシフトをスタッフがまだ見ていない</td><td>通常連絡手段で声かけ</td></tr></tbody></table><p>未打刻の行には、店長がその場で押せるボタンがあります。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>使う場面</th><th>結果</th></tr></thead><tbody><tr><td>連絡済み</td><td>電話や通常連絡手段で本人に連絡した</td><td>未打刻のまま、対応済み表示が残る</td></tr><tr><td>遅刻連絡あり</td><td>本人から遅刻連絡があった</td><td>出勤するまで未打刻のまま、遅刻連絡あり表示が残る</td></tr><tr><td>欠勤にする</td><td>本人が来られないことが確定した</td><td>承認済み欠勤へ移り、未打刻から外れる</td></tr><tr><td>穴埋め</td><td>欠勤確定後すぐ人を探したい</td><td>欠勤処理後、候補確認、空きシフト募集、他店舗ヘルプへ進める</td></tr></tbody></table><table tabindex="0"><thead><tr><th>表示</th><th>意味</th><th>対応</th></tr></thead><tbody><tr><td>開始済み未打刻</td><td>予定開始から 15 分超過しても出勤打刻がない</td><td>本人確認、打刻漏れ修正、必要なら欠勤扱い</td></tr><tr><td>未対応の交代/欠勤</td><td>スタッフから申請が来ているが、店長がまだ対応していない</td><td>承認または却下</td></tr><tr><td>承認済み欠勤</td><td>欠勤だけ承認され、交代スタッフが入っていない</td><td>呼べる候補または店舗間ヘルプで穴埋め</td></tr><tr><td>時間帯不足</td><td>テンプレート必要人数に対して当日の予定人数が不足</td><td>シフト追加、ヘルプ要請</td></tr><tr><td>今日呼べる候補</td><td>今日シフトが入っていない同店舗スタッフ</td><td>電話や通常連絡手段で確認</td></tr></tbody></table><h3 id="スタッフから交代依頼が来た場合" tabindex="-1">スタッフから交代依頼が来た場合 <a class="header-anchor" href="#スタッフから交代依頼が来た場合" aria-label="Permalink to &quot;スタッフから交代依頼が来た場合&quot;">​</a></h3><ol><li>【当日・ヘルプ】 → <strong>交代・欠勤申請</strong> を見る</li><li>対象行の <strong>承認</strong> を押す</li><li>交代スタッフ候補から選ぶ</li><li><strong>承認</strong> を押す</li><li>元のシフト担当者が交代スタッフに差し替わる</li></ol><p>候補がいない場合、交代なしで承認することもできます。その場合は欠員として当日不足に残ります。</p><h3 id="スタッフから欠勤連絡が来た場合" tabindex="-1">スタッフから欠勤連絡が来た場合 <a class="header-anchor" href="#スタッフから欠勤連絡が来た場合" aria-label="Permalink to &quot;スタッフから欠勤連絡が来た場合&quot;">​</a></h3><ol><li>【当日・ヘルプ】 → <strong>交代・欠勤申請</strong> を見る</li><li>理由を確認する</li><li>交代スタッフを入れられる場合は選んで承認</li><li>交代なしなら、そのまま承認</li><li>必要なら今日呼べる候補、または店舗間ヘルプを使う</li></ol><p>欠勤連絡を承認しても、外部メッセージ通知は自動送信されません。本人への連絡や最終確認は店舗の通常連絡手段で行ってください。</p><h2 id="_2-9-c-空きシフト募集で穴を埋める" tabindex="-1">2-9-c. 空きシフト募集で穴を埋める <a class="header-anchor" href="#_2-9-c-空きシフト募集で穴を埋める" aria-label="Permalink to &quot;2-9-c. 空きシフト募集で穴を埋める&quot;">​</a></h2><p>急な欠勤、予約増、仕込み増で人が足りない時は、いきなり週間カレンダーへ誰かを入れるのではなく、まず <strong>空きシフト募集</strong> を使えます。</p><h3 id="店長が募集を作る" tabindex="-1">店長が募集を作る <a class="header-anchor" href="#店長が募集を作る" aria-label="Permalink to &quot;店長が募集を作る&quot;">​</a></h3><ol><li>管理画面 → 【シフト管理】 → <strong>【当日・ヘルプ】</strong></li><li><strong>現場シフト運用</strong> の <strong>【募集作成】</strong></li><li>入力: <ul><li>日付</li><li>開始時刻</li><li>終了時刻</li><li>休憩</li><li>持ち場</li><li>必要スキル（任意）</li><li>メモ</li></ul></li><li><strong>【作成】</strong></li></ol><h3 id="スタッフが応募する" tabindex="-1">スタッフが応募する <a class="header-anchor" href="#スタッフが応募する" aria-label="Permalink to &quot;スタッフが応募する&quot;">​</a></h3><ol><li>スタッフが管理画面 → 【シフト管理】 → <strong>【マイシフト】</strong></li><li><strong>募集シフト</strong> を見る</li><li>入れる募集の <strong>【応募】</strong></li><li>店長へのメモがあれば入力</li><li>応募済みになる</li></ol><h3 id="店長が承認する" tabindex="-1">店長が承認する <a class="header-anchor" href="#店長が承認する" aria-label="Permalink to &quot;店長が承認する&quot;">​</a></h3><ol><li>【当日・ヘルプ】 → 現場シフト運用 → 空きシフト募集</li><li>応募者の <strong>【承認】</strong></li><li>POSLA がそのスタッフのシフトを自動作成</li><li>募集は締め切りになり、他の応募は却下される</li></ol><p>注意点:</p><ul><li>応募だけではシフトになりません。店長の承認が必要です。</li><li>同時間帯に既存シフトがあるスタッフは応募・承認できません。</li><li>必要スキル付き募集は、そのスキルを持つスタッフだけが応募できます。</li><li>承認後のシフトは通常の週間カレンダーで修正できます。</li></ul><h2 id="_2-9-d-今日の担当作業を割り振る" tabindex="-1">2-9-d. 今日の担当作業を割り振る <a class="header-anchor" href="#_2-9-d-今日の担当作業を割り振る" aria-label="Permalink to &quot;2-9-d. 今日の担当作業を割り振る&quot;">​</a></h2><p>「誰がレジ開けをやったか」「中間清掃は誰か」「閉店清掃が終わったか」を口頭だけで回すと抜けます。担当作業は、1 タップ完了で現場の迷いを減らすための機能です。</p><h3 id="店長が担当作業を追加する" tabindex="-1">店長が担当作業を追加する <a class="header-anchor" href="#店長が担当作業を追加する" aria-label="Permalink to &quot;店長が担当作業を追加する&quot;">​</a></h3><ol><li>【シフト管理】 → <strong>【当日・ヘルプ】</strong></li><li>現場シフト運用 → <strong>今日の担当作業</strong></li><li><strong>【作業追加】</strong></li><li>作業テンプレート、担当スタッフ、メモを入力</li><li><strong>【追加】</strong></li></ol><p>初期テンプレート:</p><table tabindex="0"><thead><tr><th>作業</th><th>用途</th></tr></thead><tbody><tr><td>レジ開け</td><td>開店時のレジ準備</td></tr><tr><td>開店前チェック</td><td>店内・端末・予約確認</td></tr><tr><td>中間清掃</td><td>営業中の清掃</td></tr><tr><td>レジ締め</td><td>閉店時のレジ締め</td></tr><tr><td>閉店清掃</td><td>閉店作業</td></tr></tbody></table><h3 id="スタッフが完了する" tabindex="-1">スタッフが完了する <a class="header-anchor" href="#スタッフが完了する" aria-label="Permalink to &quot;スタッフが完了する&quot;">​</a></h3><ol><li>スタッフが 【マイシフト】 を開く</li><li><strong>担当作業</strong> を見る</li><li>終わった作業の <strong>【完了】</strong></li><li>間違えたら <strong>【戻す】</strong></li></ol><p>端末アカウントではなく、スタッフ本人のアカウントでマイシフトを開いて完了します。ハンディ/KDS/レジの device アカウントは、シフトや作業完了の「人」としては扱いません。</p><h2 id="_2-9-e-スキル不足・休憩不足を見る" tabindex="-1">2-9-e. スキル不足・休憩不足を見る <a class="header-anchor" href="#_2-9-e-スキル不足・休憩不足を見る" aria-label="Permalink to &quot;2-9-e. スキル不足・休憩不足を見る&quot;">​</a></h2><p>当日・ヘルプの現場シフト運用には、次の不足がまとまります。</p><table tabindex="0"><thead><tr><th>表示</th><th>店長が見ること</th><th>対応</th></tr></thead><tbody><tr><td>スキル不足</td><td>持ち場に必要なスキル人数が足りない</td><td>スキル保有者を入れる、店長が入る、持ち場条件を見直す</td></tr><tr><td>休憩不足</td><td>6 時間超/8 時間超の休憩が足りない</td><td>休憩時間を入力、休憩に出せる時間を作る</td></tr><tr><td>経験者なし</td><td>その時間帯が新人・勤務実績少なめの人だけ</td><td>経験者を入れる、店長がフォローする</td></tr><tr><td>人件費率超過</td><td>今日の予定人件費が売上に対して重い</td><td>シフト時間、予約、売上見込みを確認</td></tr><tr><td>希望未提出</td><td>直近 7 日の希望が未提出</td><td>通常連絡手段で提出依頼</td></tr></tbody></table><p>POSLA は不足を見つけますが、勝手にシフトを入れ替えません。飲食店では「今日は予約がある」「新人研修中」「店長がキッチンに入る」など画面外の事情があるため、最終判断は店長が行います。</p><h2 id="_2-10-シフト希望の提出-スタッフ側" tabindex="-1">2-10. シフト希望の提出（スタッフ側） <a class="header-anchor" href="#_2-10-シフト希望の提出-スタッフ側" aria-label="Permalink to &quot;2-10. シフト希望の提出（スタッフ側）&quot;">​</a></h2><p>スタッフが自分の希望シフトを提出する機能。</p><h3 id="手順-2" tabindex="-1">手順 <a class="header-anchor" href="#手順-2" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>スタッフが管理画面にログイン</li><li>【シフト管理】 → サブタブ <strong>【希望提出】</strong></li><li>カレンダー表示</li><li>希望日をタップ → 時間帯入力（例: 10:00〜15:00 希望）</li><li><strong>【保存】</strong></li><li>マネージャーがシフト作成時に参考にする</li></ol><hr><h2 id="_2-11-シフト集計-労働時間・人件費" tabindex="-1">2-11. シフト集計（労働時間・人件費） <a class="header-anchor" href="#_2-11-シフト集計-労働時間・人件費" aria-label="Permalink to &quot;2-11. シフト集計（労働時間・人件費）&quot;">​</a></h2><h3 id="手順-3" tabindex="-1">手順 <a class="header-anchor" href="#手順-3" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>【シフト管理】 → サブタブ <strong>【集計サマリー】</strong></li><li>期間を指定（日次 / 週次 / 月次）</li><li>以下が表示:</li></ol><table tabindex="0"><thead><tr><th>指標</th><th>説明</th></tr></thead><tbody><tr><td>総労働時間</td><td>全スタッフの合計実働時間</td></tr><tr><td>人件費</td><td><code>hourly_rate × 実働時間</code> の合計</td></tr><tr><td>人件費率</td><td>実績人件費 ÷ 期間内の実売上</td></tr><tr><td>スタッフ別労働時間</td><td>個別の実働時間</td></tr><tr><td>労基法警告</td><td>週 40 時間超過、月 80 時間残業等があればアラート</td></tr><tr><td>深夜労働時間</td><td>22:00〜05:00 の時間（深夜割増対象）</td></tr></tbody></table><hr><h2 id="_2-12-スタッフ向けマイシフト閲覧" tabindex="-1">2-12. スタッフ向けマイシフト閲覧 <a class="header-anchor" href="#_2-12-スタッフ向けマイシフト閲覧" aria-label="Permalink to &quot;2-12. スタッフ向けマイシフト閲覧&quot;">​</a></h2><p>スタッフが自分の確定シフトを見る機能です。自分以外のシフトは見えません。</p><ol><li>スタッフが管理画面にログイン</li><li>【シフト管理】 → サブタブ <strong>【マイシフト】</strong></li><li>自分のシフトだけがカレンダーで見える</li><li>問題なければ <strong>確認</strong> を押す</li><li>ステータスが <strong>確認済</strong> になる</li></ol><h3 id="_2-12-1-交代依頼を出す" tabindex="-1">2-12-1. 交代依頼を出す <a class="header-anchor" href="#_2-12-1-交代依頼を出す" aria-label="Permalink to &quot;2-12-1. 交代依頼を出す&quot;">​</a></h3><ol><li>【マイシフト】で対象シフトを探す</li><li><strong>交代依頼</strong> を押す</li><li>候補スタッフが表示される</li><li>候補を選ぶ、または候補を指定しない</li><li>店長へのメモを入力</li><li><strong>送信</strong></li></ol><p>申請後は対象シフトに <strong>申請中</strong> と表示されます。店長が承認するまでは、シフト担当者は変わりません。</p><h3 id="_2-12-1-b-シフトが変更された場合" tabindex="-1">2-12-1-b. シフトが変更された場合 <a class="header-anchor" href="#_2-12-1-b-シフトが変更された場合" aria-label="Permalink to &quot;2-12-1-b. シフトが変更された場合&quot;">​</a></h3><p>スタッフが一度 <strong>確認済</strong> にしたシフトでも、店長があとから時間、休憩、持ち場、メモを変更すると、その人だけ <strong>変更あり</strong> に戻ります。</p><p>スタッフの操作:</p><ol><li>【マイシフト】を開く</li><li><strong>変更あり</strong> のシフトを見る</li><li><code>10:00 → 10:30</code> のような変更前後を確認する</li><li>問題なければ <strong>確認</strong> を押す</li></ol><p>店長が「再確認」ボタンを押す必要はありません。POSLA が変更を検知して自動で対象スタッフだけに出します。</p><h3 id="_2-12-2-欠勤連絡を出す" tabindex="-1">2-12-2. 欠勤連絡を出す <a class="header-anchor" href="#_2-12-2-欠勤連絡を出す" aria-label="Permalink to &quot;2-12-2. 欠勤連絡を出す&quot;">​</a></h3><ol><li>【マイシフト】で対象シフトを探す</li><li><strong>欠勤連絡</strong> を押す</li><li>理由や店長へのメモを入力</li><li>送信</li></ol><p>欠勤連絡を出しただけでは、シフトが自動削除されるわけではありません。店長が当日・ヘルプで承認または却下します。</p><h3 id="_2-12-3-欠勤が承認された後の穴埋め" tabindex="-1">2-12-3. 欠勤が承認された後の穴埋め <a class="header-anchor" href="#_2-12-3-欠勤が承認された後の穴埋め" aria-label="Permalink to &quot;2-12-3. 欠勤が承認された後の穴埋め&quot;">​</a></h3><p>店長が欠勤を <strong>交代なし</strong> で承認した場合、当日・ヘルプに <strong>穴埋め</strong> ボタンが出ます。</p><ol><li>【当日・ヘルプ】 → <strong>交代・欠勤申請</strong></li><li>承認済み欠勤の <strong>穴埋め</strong> を押す</li><li>同店舗候補を見る</li><li>候補がいない場合: <ul><li><strong>空きシフト募集を作成</strong></li><li>または <strong>他店舗ヘルプ要請</strong></li></ul></li></ol><p>空きシフト募集を作る場合は、欠勤したシフトと同じ日付、時間、持ち場が自動で入ります。店長は内容を確認するだけで済みます。</p><hr><h2 id="_2-13-よくある質問" tabindex="-1">2-13. よくある質問 <a class="header-anchor" href="#_2-13-よくある質問" aria-label="Permalink to &quot;2-13. よくある質問&quot;">​</a></h2><p><strong>Q1. 既存のスタッフアカウントを KDS タブレットでログインしっぱなしにしてはダメ？</strong></p><p>A1. <strong>強く非推奨</strong>。シフト・勤怠・スタッフ評価レポートが全部そのスタッフ名義になってしまい、データが壊れます。必ず device アカウントを作って運用してください。</p><p><strong>Q2. device アカウントは何個まで作れる？</strong></p><p>A2. 上限なし。店舗の KDS 台数 + レジ台数 + ハンディ台数分作ってください。例: 3 店舗 × 各 KDS 2 台・レジ 1 台・ハンディ 3 台 = 18 個。</p><p><strong>Q3. device アカウントはシフト管理に影響しない？</strong></p><p>A3. 影響しません。デバイスアカウントはシフト・勤怠・人件費・スタッフ評価の対象外です。</p><p><strong>Q4. 退職したスタッフのアカウント、削除すべき？</strong></p><p>A4. 無効化推奨（トグル OFF）。過去の勤怠・注文履歴を守るため。完全削除は非推奨。</p><p><strong>Q5. GPS 打刻の精度が悪い</strong></p><p>A5. 室内では GPS が 5〜50m ずれることがあります。許容半径を 300〜500m に広げるか、GPS 必須を OFF にして監査ログで確認してください。</p><p><strong>Q6. スタッフが勤怠打刻を忘れた</strong></p><p>A6. まずスタッフ本人に、スタッフ画面の <strong>勤怠履歴・修正申請</strong> から申請してもらいます。店長は【勤怠一覧】上部の申請を承認できます。急ぎの場合は、マネージャーが【勤怠一覧】の該当日を <strong>【編集】</strong> で手動修正できます。</p><p><strong>Q7. AI シフト提案の質が悪い</strong></p><p>A7. 過去データの蓄積が少ないと AI 精度が低くなります。最低 30 日分のデータが溜まってから使うのが現実的です。</p><p><strong>Q8. 交代依頼を承認したら、元のスタッフのシフトはどうなる？</strong></p><p>A8. 交代スタッフを選んで承認すると、対象シフトの担当者が交代スタッフに差し替わります。交代なしで承認した場合は欠勤だけが承認され、当日の不足として残ります。</p><p><strong>Q9. マイシフトの「確認済」は外部メッセージの既読ですか？</strong></p><p>A9. 違います。POSLA のマイシフト画面でスタッフが <strong>確認</strong> を押した状態です。LINE やメールの既読とは連動しません。</p><hr><h2 id="_2-14-付録-ロール作成権限マトリクス" tabindex="-1">2-14. 付録: ロール作成権限マトリクス <a class="header-anchor" href="#_2-14-付録-ロール作成権限マトリクス" aria-label="Permalink to &quot;2-14. 付録: ロール作成権限マトリクス&quot;">​</a></h2><table tabindex="0"><thead><tr><th>作成者 \\ 作成対象</th><th>owner</th><th>manager</th><th>staff</th><th>device</th></tr></thead><tbody><tr><td><strong>owner</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>manager</strong></td><td>❌</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td><strong>staff</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><hr><h2 id="_2-15-次のページへ" tabindex="-1">2-15. 次のページへ <a class="header-anchor" href="#_2-15-次のページへ" aria-label="Permalink to &quot;2-15. 次のページへ&quot;">​</a></h2><p>→ <a href="./part3-menu.html">Part 3: メニュー管理</a></p>',231)])])}const p=r(i,[["render",d]]);export{b as __pageData,p as default};
